<?php require_once '../config/db.php'; require_once '../includes/auth.php'; require_admin(); $page_title='Reports and Views'; require_once '../includes/header.php'; require_once '../includes/sidebar.php'; function render($conn,$title,$desc,$sql){ echo '<div class="card" style="margin-top:18px"><h2>'.safe($title).'</h2><p>'.safe($desc).'</p></div>'; $r=mysqli_query($conn,$sql); echo '<div class="table-wrap"><table>'; if($r && mysqli_num_rows($r)>0){ $first=true; while($row=mysqli_fetch_assoc($r)){ if($first){ echo '<tr>'; foreach(array_keys($row) as $h) echo '<th>'.safe($h).'</th>'; echo '</tr>'; $first=false;} echo '<tr>'; foreach($row as $v) echo '<td>'.safe($v).'</td>'; echo '</tr>'; } } echo '</table></div>'; } render($conn,'View 1: Active Member Report','Shows active members with plans and payment information.','SELECT * FROM view_active_member_report'); render($conn,'View 2: Trainer Workload Report','Shows trainer workload, diet plans, workout plans, and average rating.','SELECT * FROM view_trainer_workload_report'); render($conn,'View 3: Equipment Usage Report','Shows equipment usage count in workout plans.','SELECT * FROM view_equipment_usage_report'); require_once '../includes/footer.php'; ?>
